  SnippetsIcon,
  TerminalIcon,
  WindowIcon,
} from '../components/icons/icons';
import type { SectionData } from '../types';

export const MOCK_SECTIONS: SectionData[] = [
  {
    title: 'Suggestions',
    items: [
      {
        id: 'clipboard-history',
